<style>
/* width */
.image-container::-webkit-scrollbar {
height: .5rem;
}

/* Track */
.image-container::-webkit-scrollbar-track {
background: rgba(255, 255, 255, 0.121);
}

/* Handle */
.image-container::-webkit-scrollbar-thumb {
background: white;
border-radius: 4rem;
}

/* Handle on hover */
.image-container::-webkit-scrollbar-thumb:hover {
background: rgb(34 211 238);
}

.content{
    opacity: 0;
    filter: blur(40px);
    transform: translateX(50%);
}

.animate {
  animation: animate .4s ease-in-out forwards;
}

@keyframes animate {
  from {
    opacity: 0;
    filter: blur(40px);
    transform: translateX(50%);
  }
  to {
    opacity: 1;
    filter: blur(0px);
    transform: translateY(0);
  }
}
</style>

<script>
  import Back from '../../components/Back.vue';
  import Card from '../../components/Card.vue';
  
  export default {
    components:{
      Back,
      Card
    },
  mounted() {
    document.addEventListener('scroll', this.scrollDetector);
  },
  methods:{
    scrollDetector(){
        // var el = document.querySelector("#first-design");
        var div_list = document.querySelectorAll('.content');
        var els = [...div_list]; 
        els.forEach(el => {
            this.onView(el);
        });
    },
    onView(element){
        var windowHeight = window.innerHeight;
        var scrollY = window.scrollY || window.pageYOffset;
        var scrollPosition = scrollY + windowHeight;
        var elementPosition = element.getBoundingClientRect().top + scrollY;

        if (scrollPosition+20 > elementPosition) {
            element.classList.add('animate');
        }
    }
}
}
</script>